import random

class EvolutionStrategy:
    def __init__(self, population_size, mutation_rate):
        self.population_size = population_size
        self.mutation_rate = mutation_rate
        self.genome_length = 10
        self.genomes = [random.randint(0, 2) for _ in range(population_size)]
    
    def evolve(self):
        new_population = []
        for i in range(self.population_size):
            parent_a = random.choice(self.genomes)
            parent_b = random.choice(self.genomes)
            offspring = crossover(parent_a, parent_b)
            offspring = mutate(offspring)
            new_population.append(offspring)
        self.genomes = new_population
    
    def crossover(parent_a, parent_b):
        crossover_point = random.randint(0, self.genome_length - 1)
        return parent_a[:crossover_point] + parent_b[crossover_point:]
    
    def mutate(genome):
        for i in range(self.genome_length):
            if random.random() < self.mutation_rate:
                genome[i] = (genome[i] + 1) % 3
        return genome

